'use client'

import { useState, useEffect } from 'react'
import { useSearchParams } from 'next/navigation'
import type { Restaurant } from '@food-app/shared'
import { Navbar } from '@/components/layout/Navbar'
import { RestaurantCard } from '@/components/restaurant/RestaurantCard'
import { Spinner } from '@/components/ui/Spinner'
import { useLocation } from '@/context/LocationContext'

const CUISINES = [
  { label: 'All', icon: '🍽️' },
  { label: 'Yoruba', icon: '🍲' },
  { label: 'Hausa', icon: '🔥' },
  { label: 'Lagos', icon: '🌶️' },
  { label: 'Igbo', icon: '🫕' },
]

const SORT_OPTIONS = ['Recommended', 'Rating', 'Delivery time', 'Delivery fee']

export default function RestaurantsPage() {
  const searchParams = useSearchParams()
  const [restaurants, setRestaurants] = useState<Restaurant[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState(searchParams.get('q') ?? '')
  const [cuisine, setCuisine] = useState('All')
  const [sort, setSort] = useState('Recommended')
  const { location, openModal } = useLocation()

  useEffect(() => {
    setSearch(searchParams.get('q') ?? '')
  }, [searchParams])

  useEffect(() => {
    fetch('/api/restaurants')
      .then((r) => r.json())
      .then((data) => setRestaurants(data.restaurants))
      .finally(() => setLoading(false))
  }, [])

  const filtered = restaurants.filter((r) => {
    const matchSearch =
      r.name.toLowerCase().includes(search.toLowerCase()) ||
      r.cuisine.toLowerCase().includes(search.toLowerCase())
    const matchCuisine = cuisine === 'All' || r.cuisine === cuisine
    return matchSearch && matchCuisine
  })

  return (
    <>
      <Navbar />

      {/* Location bar */}
      <div className="relative z-10 bg-[var(--surface)] border-b border-[var(--border)]">
        <div className="mx-auto max-w-7xl px-4 py-2.5 flex items-center gap-2">
          <span className="text-base">{location.flag}</span>
          <span className="text-sm font-semibold text-[var(--text-2)]">
            Delivering to: <span className="text-[var(--text)]">{location.city}, {location.country}</span>
          </span>
          <button
            onClick={openModal}
            className="ml-1 text-xs font-bold text-[var(--gold)] hover:underline transition-colors"
          >
            Change
          </button>
        </div>
      </div>

      <main className="relative z-10 mx-auto max-w-7xl px-4 py-8">

        {/* Search */}
        <div className="relative mb-6">
          <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-[var(--text-3)]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          <input
            type="text"
            placeholder="Search restaurants or dishes..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-12 pr-4 py-4 rounded-2xl bg-[var(--surface)] border border-[var(--border)] text-[var(--text)] placeholder-[var(--text-3)] text-sm focus:outline-none focus:border-[var(--gold)] focus:ring-1 focus:ring-[var(--gold)] transition-colors"
          />
        </div>

        {/* Cuisine filters */}
        <div className="flex gap-2 overflow-x-auto pb-2 mb-6">
          {CUISINES.map((c) => (
            <button
              key={c.label}
              onClick={() => setCuisine(c.label)}
              className={`flex items-center gap-2 shrink-0 rounded-2xl px-4 py-2.5 text-sm font-semibold transition-all ${
                cuisine === c.label
                  ? 'bg-[var(--gold)] text-[var(--gold-text)]'
                  : 'bg-[var(--surface)] border border-[var(--border)] text-[var(--text-2)] hover:border-[var(--gold)]/50 hover:text-[var(--text)]'
              }`}
            >
              <span>{c.icon}</span>
              <span>{c.label}</span>
            </button>
          ))}
        </div>

        {/* Sort + count */}
        <div className="flex items-center justify-between mb-6">
          <p className="text-sm text-[var(--text-3)]">
            {loading ? '' : `${filtered.length} restaurant${filtered.length !== 1 ? 's' : ''} found`}
          </p>
          <div className="flex gap-2">
            {SORT_OPTIONS.map((s) => (
              <button
                key={s}
                onClick={() => setSort(s)}
                className={`hidden sm:block rounded-xl px-3 py-1.5 text-xs font-semibold transition-all ${
                  sort === s
                    ? 'bg-[var(--gold)] text-[var(--gold-text)]'
                    : 'bg-[var(--surface)] border border-[var(--border)] text-[var(--text-2)] hover:border-[var(--gold)]/50'
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>

        {/* Results */}
        {loading ? (
          <div className="flex flex-col items-center justify-center py-24 gap-4">
            <Spinner className="h-8 w-8 text-[var(--gold)]" />
            <p className="text-sm text-[var(--text-3)]">Finding restaurants near you...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="py-24 text-center">
            <p className="text-5xl mb-4">🍽️</p>
            <p className="text-lg font-bold text-[var(--text)]">No restaurants found</p>
            <p className="text-sm text-[var(--text-3)] mt-1">Try a different search or remove filters</p>
            <button
              onClick={() => { setSearch(''); setCuisine('All') }}
              className="mt-4 px-6 py-2.5 bg-[var(--gold)] hover:bg-[var(--gold-h)] rounded-xl text-sm font-black text-[var(--gold-text)] transition-colors"
            >
              Clear filters
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
            {filtered.map((r) => (
              <RestaurantCard key={r.id} restaurant={r} />
            ))}
          </div>
        )}
      </main>
    </>
  )
}
